{
    "level": "A1–B1",
    "intro": "W tej sekcji poznasz główne typy pytań po angielsku: od prostych yes / no questions po negative questions i question tags.",
    "rules": [
        {
            "label": "Yes / No",
            "color": "emerald",
            "text": "<strong>Pytania ogólne</strong> z odpowiedzią yes albo no:",
            "example": "Do you like coffee?"
        },
        {
            "label": "Wh",
            "color": "blue",
            "text": "<strong>Wh-questions</strong> ze słowami pytającymi:",
            "example": "What do you want?"
        },
        {
            "label": "Tags / przeczenia",
            "color": "rose",
            "text": "<strong>Question tags</strong> i <strong>negative questions</strong> dodają potwierdzenie, zdziwienie albo oczekiwanie:",
            "example": "You know him, don't you? / Don't you know him?"
        }
    ]
}
